(window.webpackJsonp=window.webpackJsonp||[]).push([[296],{923:function(n,r){n.exports='\x3c!-- \r\ntitle: 04-Python高级函数与装饰器\r\nsort: \r\n--\x3e \r\n## 高阶函数\r\n\r\n- `f=abs`函数可以赋值给变量。\r\n- `abs=10`函数名可以指向其他对象.\r\n- 高阶函数：接收另一个函数为参数\r\n\r\n### map/reduce()\r\n\r\n- `map()`函数接收两个参数，一个是函数，一个是`Iterable`。\r\n\r\n- `map`将传入的函数依次作用到序列的每个元素，并把结果作为新的`Iterator`返回。\r\n\r\n- `reduce`把一个函数作用在序列上。并把结果与下一个元素做累计计算。\r\n\r\n- ```python\r\n  from functools import reduce\r\n  \r\n  l = [1, 4, 8, 20, 52]\r\n  \r\n  def my_pow(i):\r\n      return i**2\r\n  \r\n  def my_add(x, y):\r\n      return x+y\r\n  \r\n  print(reduce(my_add, map(my_pow, l)))\r\n  ```\r\n\r\n### filter()\r\n\r\n- 根据返回值的`T/F`决定保留还是丢弃该元素。\r\n\r\n- 返回值是一个`Iterator`,需要用`list()`\r\n\r\n  ```python\r\n  def del_odd(i):\r\n      return i % 2 == 0\r\n  \r\n  l = [1, 2, 3, 4, 5, 6]\r\n  print(list(filter(del_odd, l)))z\r\n  ```\r\n\r\n### sorted()\r\n\r\n- 排序函数\r\n\r\n- 可以根据`key`来决定排序方式。\r\n\r\n- 可以使用`reverse`参数进行反向排序。\r\n\r\n  ```python\r\n  example_list = [-4, -2, -1, 0, 3, 6]\r\n  print(sorted(example_list, key=lambda x: x*-1))\r\n  ```\r\n\r\n## 闭包\r\n\r\n- `return function`返回一个函数，下回调用时求值。\r\n\r\n- 即使传入相同参数，每次调用都返回一个新的函数。\r\n\r\n- **闭包**\r\n\r\n  > **将函数内的变量即内部函数`return`到外面**\r\n  >\r\n  > 返回函数不要引用任何循环变量，或者后续会发生变化的变量。\r\n  >\r\n  > 因为函数不会立即执行。除非创建新函数\r\n  >\r\n  > 否则所有变量都将为最终值。\r\n\r\n- 从函数中返回函数\r\n\r\n  ```python\r\n  def hi(name=\'fzf\'):\r\n      def admin():\r\n          return "hello admin"\r\n  \r\n      def guest():\r\n          return "hello guset"\r\n      if name == \'fzf\':\r\n          return admin\r\n      else:\r\n          return guest\r\n  \r\n  \r\n  a = hi()\r\n  print(a())\r\n  ```\r\n\r\n - 装饰器\r\n\r\n   ```python\r\n   def hi(func, name=\'fzf\'):\t\t# 装饰函数\r\n       def admin():\r\n           print("hello admin")\r\n           func()\r\n           print("bye admin")\r\n   \r\n       def guest():\r\n           print("hello %s" % name)\r\n           func()\r\n           print("bye %s" % name)\r\n   \r\n       if name == \'fzf\':\r\n           return admin\r\n       else:\r\n           return guest\r\n   \r\n   \r\n   def opera():\r\n       print("i want to kill you!")\r\n   \r\n   \r\n   a = hi(opera, name="pig")\r\n   a()\r\n   ```\r\n\r\n- 使用`@`\r\n\r\n  ```python\r\n  def hi(func, name=\'fzf\'):\t\t# 装饰函数\r\n      def admin():\r\n          print("hello admin")\r\n          func()\r\n          print("bye admin")\r\n  \r\n      def guest():\r\n          print("hello %s" % name)\r\n          func()\r\n          print("bye %s" % name)\r\n  \r\n      if name == \'fzf\':\r\n          return admin\r\n      else:\r\n          return guest\r\n  \r\n  @hi\r\n  def opera():\r\n      print("i want to kill you!")\r\n  \r\n  opera()\r\n  ```\r\n\r\n- name\r\n\r\n  ```python\r\n  print(opera.__name__)\r\n  > admin\r\n  # 打印函数名发现名称变了\r\n  # 可使用wraps\r\n  from functools import wraps\r\n  def hi(func, name=\'fzf\'):\r\n      @wraps(func)\r\n      ...\r\n  ```\r\n\r\n - **最基础的闭包+装饰器：**\r\n\r\n  ```python\r\nfrom functools import wraps\r\n\r\n\r\ndef decorator_name(f):\r\n    @wraps(f)\r\n    def decorated(*args, **kwargs):\r\n        if not can_run:\r\n            return "Function will not run"\r\n        return f(*args, **kwargs)\t# 运行原函数\r\n    return decorated\t\t# 返回修饰好的函数\r\n\r\n\r\n@decorator_name\r\ndef func():\r\n    return("Function is running")\r\n\r\n\r\ncan_run = True\r\nprint(func())\r\n# Output: Function is running\r\n\r\ncan_run = False\r\nprint(func())\r\n# Output: Function will not run\r\n  ```\r\n\r\n- 高阶带参数\r\n\r\n  ```python\r\n  def log(name):\r\n      def hi(func):\t\t# 装饰函数\r\n          def admin():\r\n              print("hello admin")\r\n              func()\r\n              print("bye admin")\r\n  \r\n          def guest():\r\n              print("hello %s" % name)\r\n              func()\r\n              print("bye %s" % name)\r\n  \r\n          if name == \'fzf\':\r\n              return admin\r\n          else:\r\n              return guest\r\n     return hi\r\n  \r\n  \r\n  @log(\'pig\')\r\n  def opera():\r\n      print("i want to kill you!")\r\n  \r\n  opera()\r\n  ```\r\n\r\n\r\n## 匿名函数\r\n\r\n- 匿名函数`lambda x: x * x`实际上就是：\r\n\r\n  ```python\r\n  def f(x):\r\n      return x * x\r\n  ```\r\n\r\n- 可以把一个匿名函数赋值给变量。\r\n\r\n  ```python\r\n  f = lambda x: x * x\r\n  ```\r\n\r\n## 装饰器\r\n\r\n> 装饰器必须满足函数是闭包\r\n\r\n- 在代码运行期间动态增加功能的方式。\r\n\r\n- ```python\r\n  def log(func):\t\t\t\t# decorator\r\n  \tdef wrapper(*args, **kw):\r\n  \t\tprint(\'call %s():\' % func.__name__)\r\n  \t\treturn func(*args, **kw)\r\n  \treturn wrapper\r\n  \r\n  @log\t\t\t\t\t\t# 相当于：now = log(now(*))\r\n  def now(s):\r\n  \tprint(s + \'2020-3-10\')\r\n      \r\n  now(\'现在时间：\')\r\n   \r\n  >>> \r\n  call now()\r\n  现在时间：2020-3-10\r\n  ```\r\n  \r\n- 只是将now函数名指向新的函数。\r\n\r\n- 假如decorator本身需要传入参数，需要编写返回d的高阶函数：\r\n\r\n- ```python\r\n  def log(text):\t\t# 多加一层\r\n      def decorator(func):\r\n          def wrapper(*args, **kw):\r\n              print(\'%s %s():\' % (text, func.__name__))\r\n              return func(*args, **kw)\r\n          return wrapper\r\n      return decorator\r\n      \r\n  @log(\'execute\')\t\t\t\t# 相当于：now = log(\'execute\')(now)\r\n  def now():\r\n      print(\'2015-3-25\')\r\n  \r\n  >>> now()\r\n  execute now():\r\n  2015-3-25\r\n  ```\r\n\r\n- 为了保留`func.__name__`属性，可使用`functools.wraps`函数。\r\n\r\n- ```python\r\n  import functools\r\n  \r\n  def log(text):\r\n      def decorator(func):\r\n          @functools.wraps(func)\t\t\r\n          def wrapper(*args, **kw):\r\n              print(\'%s %s():\' % (text, func.__name__))\r\n              return func(*args, **kw)\r\n          return wrapper\r\n      return decorator\r\n  ```\r\n\r\n## 偏函数\r\n\r\n- 为一个函数设置默认传入参数。\r\n\r\n- ```python\r\n  int2 = functools.partial(int, base=2)\r\n  #相当于\r\n  def int2(x, base = 2):\r\n      return int(x, base)\r\n  # 将二进制转为十进制\r\n  print(int2(\'1001\'))\r\n  ```\r\n\r\n- 使用`functools.partial`可以固定住原函数的部分参数，从而在调用时更简单。\r\n\r\n## 模块\r\n\r\n- ```python\r\n  if __name__==\'__main__\':\t\t# 判断是否直接运行\r\n      start()\r\n  ```\r\n\r\n- `__x__`这样的变量时特殊变量，可以被引用。\r\n\r\n- `__x`这样的变量时非公开的，不应直接引用。\r\n'}}]);